              )}

              {/* Info Card */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">What is Keyword Density?</CardTitle>
                </CardHeader>
                <CardContent className="space-y-2 text-sm text-muted-foreground">
                  <p>
