import { storage } from "../storage";
import type { SeoScore } from "@shared/schema";

export class SeoScoreCalculator {
  /**
   * Calculate Technical SEO Score (35% weight)
   * Based on recent SEO Health Audits for the domain
   */
  private async calculateTechnicalScore(userId: string, domain: string): Promise<number> {
    try {
      const audits = await storage.getAuditsByUserId(userId);

      // Filter audits for this domain (match domain in URL)
      const domainAudits = audits.filter(audit => {
        try {
          const url = new URL(audit.url);
          return url.hostname === domain || url.hostname === `www.${domain}` || audit.url.includes(domain);
        } catch {
          return audit.url.includes(domain);
        }
      });

      if (domainAudits.length === 0) {
        return 0; // No audits = 0 score
      }

      // Get the most recent audit score
      const latestAudit = domainAudits.sort((a, b) => 
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      )[0];

      return latestAudit.score;
    } catch (error) {
      console.error('Error calculating technical score:', error);
      return 0;
    }
  }

  /**
   * Calculate Ranking Performance Score (30% weight)
   * Based on keyword rankings - lower ranks = higher score
   */
  private async calculateRankingScore(userId: string, domain: string): Promise<number> {
    try {
      const keywords = await storage.getKeywordsByUserId(userId);

      // Filter keywords for this domain
      const domainKeywords = keywords.filter(kw => 
        kw.targetUrl.includes(domain)
      );

      if (domainKeywords.length === 0) {
        return 0; // No keywords tracked = 0 score
      }

      let totalScore = 0;
      let keywordsWithRank = 0;

      for (const keyword of domainKeywords) {
        const snapshots = await storage.getRankSnapshotsByKeywordId(keyword.id);

        if (snapshots.length > 0) {
          // Get latest snapshot
          const latest = snapshots.sort((a, b) => 
            new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
          )[0];

          if (latest.rank) {
            // Score: rank 1-10 = 100, rank 11-30 = 70, rank 31-50 = 40, rank 51-100 = 20, >100 = 5
            let rankScore = 0;
            if (latest.rank <= 10) rankScore = 100;
            else if (latest.rank <= 30) rankScore = 70;
            else if (latest.rank <= 50) rankScore = 40;
            else if (latest.rank <= 100) rankScore = 20;
            else rankScore = 5;

            totalScore += rankScore;
            keywordsWithRank++;
          }
        }
      }

      return keywordsWithRank > 0 ? Math.round(totalScore / keywordsWithRank) : 0;
    } catch (error) {
      console.error('Error calculating ranking score:', error);
      return 0;
    }
  }

  /**
   * Calculate Content Quality Score (20% weight)
   * Based on Content Planner activity - more published content = higher score
   */
  private async calculateContentScore(userId: string, domain: string): Promise<number> {
    try {
      const contentItems = await storage.getContentItemsByUserId(userId);

      if (contentItems.length === 0) {
        return 0; // No content = 0 score
      }

      // Count by status
      const published = contentItems.filter(c => c.status === 'published').length;
      const inReview = contentItems.filter(c => c.status === 'in_review').length;
      const draft = contentItems.filter(c => c.status === 'draft').length;
      const scheduled = contentItems.filter(c => c.status === 'scheduled').length;

      // Weighted scoring: published = 10 pts, scheduled = 7 pts, in_review = 5 pts, draft = 2 pts
      const score = (published * 10) + (scheduled * 7) + (inReview * 5) + (draft * 2);

      // Cap at 100, normalize based on content volume
      return Math.min(100, Math.round(score));
    } catch (error) {
      console.error('Error calculating content score:', error);
      return 0;
    }
  }

  /**
   * Calculate Activity Score (15% weight)
   * Based on overall platform engagement
   */
  private async calculateActivityScore(userId: string): Promise<number> {
    try {
      const activities = await storage.getActivitiesByUserId(userId);

      if (activities.length === 0) {
        return 0; // No activity = 0 score
      }

      // Get activities from last 30 days
      const thirtyDaysAgo = new Date();
      thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

      const recentActivities = activities.filter(a => 
        new Date(a.createdAt) >= thirtyDaysAgo
      );

      // Score based on activity frequency: 1-10 = 20, 11-25 = 40, 26-50 = 60, 51-100 = 80, >100 = 100
      const count = recentActivities.length;
      let score = 0;
      if (count <= 10) score = 20;
      else if (count <= 25) score = 40;
      else if (count <= 50) score = 60;
      else if (count <= 100) score = 80;
      else score = 100;

      return score;
    } catch (error) {
      console.error('Error calculating activity score:', error);
      return 0;
    }
  }

  /**
   * Calculate overall SEO score by aggregating all category scores
   */
  async calculateScore(userId: string, domain: string): Promise<SeoScore> {
    // Normalize domain (remove protocol, www, trailing slash)
    const normalizedDomain = domain
      .replace(/^https?:\/\//, '')
      .replace(/^www\./, '')
      .replace(/\/$/, '');

    // Calculate individual category scores
    const technicalScore = await this.calculateTechnicalScore(userId, normalizedDomain);
    const rankingScore = await this.calculateRankingScore(userId, normalizedDomain);
    const contentScore = await this.calculateContentScore(userId, normalizedDomain);
    const activityScore = await this.calculateActivityScore(userId);

    // Weighted overall score: Technical (35%), Ranking (30%), Content (20%), Activity (15%)
    const overallScore = Math.round(
      (technicalScore * 0.35) +
      (rankingScore * 0.30) +
      (contentScore * 0.20) +
      (activityScore * 0.15)
    );

    // Create metadata JSON
    const metadata = JSON.stringify({
      weights: {
        technical: '35%',
        ranking: '30%',
        content: '20%',
        activity: '15%',
      },
      calculatedAt: new Date().toISOString(),
    });

    // Save score to database
    const score = await storage.createSeoScore({
      userId,
      domain: normalizedDomain,
      overallScore,
      technicalScore,
      rankingScore,
      contentScore,
      activityScore,
      metadata,
    });

    // Record activity
    await storage.createActivity({
      userId,
      type: 'seo_score_calculated',
      description: `Calculated SEO score for ${normalizedDomain}: ${overallScore}/100`,
      metadata: { domain: normalizedDomain, score: overallScore },
    });

    return score;
  }

  /**
   * Get the latest score for a domain
   */
  async getLatestScore(userId: string, domain: string): Promise<SeoScore | null> {
    const normalizedDomain = domain
      .replace(/^https?:\/\//, '')
      .replace(/^www\./, '')
      .replace(/\/$/, '');

    return storage.getLatestSeoScore(userId, normalizedDomain);
  }

  /**
   * Get score history for a domain
   */
  async getScoreHistory(userId: string, domain: string): Promise<SeoScore[]> {
    const normalizedDomain = domain
      .replace(/^https?:\/\//, '')
      .replace(/^www\./, '')
      .replace(/\/$/, '');

    return storage.getSeoScoreHistory(userId, normalizedDomain);
  }
}

export const seoScoreCalculator = new SeoScoreCalculator();

server/services/keywordResearch.ts.content:
import * as aiWrapper from './aiWrapper';

export interface KeywordIdea {
  keyword: string;
  searchVolume: number;
  competition: number; // 0-100
  difficulty: number; // 0-100
  cpc: number; // in USD
  intent: 'informational' | 'commercial' | 'transactional' | 'navigational';
  trend: 'rising' | 'stable' | 'declining';
}

export interface KeywordResearchResult {
  seedKeyword: string;
  keywords: KeywordIdea[];
  totalResults: number;
}

export async function generateKeywordIdeas(
  seedKeyword: string,
  count: number = 50
): Promise<KeywordResearchResult> {
  const systemPrompt = "You are an expert SEO keyword researcher. Generate comprehensive, realistic keyword suggestions with accurate metrics.";

  const userPrompt = `Generate ${count} keyword ideas related to "${seedKeyword}".

For each keyword, provide:
- keyword: The keyword phrase
- searchVolume: Monthly search volume (realistic number between 100-100000)
- competition: Competition level 0-100 (0=easy, 100=very competitive)
- difficulty: SEO difficulty 0-100 (0=easy to rank, 100=very hard)
- cpc: Cost per click in USD (between 0.10 and 50.00)
- intent: Search intent (informational, commercial, transactional, or navigational)
- trend: Trend direction (rising, stable, or declining)

Include:
- 40% related keywords (variations and synonyms)
- 30% long-tail keywords (3-5 words)
- 20% question-based keywords (how, what, why, etc.)
- 10% competitor/comparison keywords

Make search volumes, competition, and CPC realistic for the niche. Use proper SEO keyword research data patterns.

Return ONLY valid JSON in this exact format:
{
  "keywords": [
    {
      "keyword": "example keyword",
      "searchVolume": 5000,
      "competition": 65,
      "difficulty": 70,
      "cpc": 2.50,
      "intent": "commercial",
      "trend": "rising"
    }
  ]
}`;

  const result = await aiWrapper.callAI(systemPrompt, userPrompt, {
    temperature: 0.7,
    maxTokens: 3000,
    jsonMode: true,
  });

  try {
    const parsed = JSON.parse(result);

    // Validate and clean the data
    const keywords: KeywordIdea[] = parsed.keywords.map((kw: any) => ({
      keyword: kw.keyword,
      searchVolume: Math.max(0, Math.round(kw.searchVolume)),
      competition: Math.min(100, Math.max(0, Math.round(kw.competition))),
      difficulty: Math.min(100, Math.max(0, Math.round(kw.difficulty))),
      cpc: Math.max(0.01, Math.min(100, parseFloat(kw.cpc.toFixed(2)))),
      intent: ['informational', 'commercial', 'transactional', 'navigational'].includes(kw.intent) 
        ? kw.intent 
        : 'informational',
      trend: ['rising', 'stable', 'declining'].includes(kw.trend) 
        ? kw.trend 
        : 'stable',
    }));

    return {
      seedKeyword,
      keywords: keywords.slice(0, count),
      totalResults: keywords.length,
    };
  } catch (error) {
    console.error('Failed to parse AI keyword research response:', error);
    throw new Error('Failed to generate keyword ideas');
  }
}

client/src/pages/SeoScoreDashboard.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Progress } from "@/components/ui/progress";
import { useToast } from "@/hooks/use-toast";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from "recharts";
import { TrendingUp, Activity, FileText, Target, BarChart3 } from "lucide-react";
import type { SeoScore } from "@shared/schema";
import { format } from "date-fns";

export default function SeoScoreDashboard() {
  const [domain, setDomain] = useState("");
  const [selectedDomain, setSelectedDomain] = useState<string | null>(null);
  const { toast } = useToast();

  const calculateMutation = useMutation({
    mutationFn: async (domainInput: string) => {
      const res = await apiRequest("POST", "/api/seo-score/calculate", { domain: domainInput });
      return await res.json();
    },
    onSuccess: (data: SeoScore) => {
      // Invalidate and refetch queries before updating state
      queryClient.invalidateQueries({ queryKey: [`/api/seo-score/${data.domain}`] });
      queryClient.invalidateQueries({ queryKey: [`/api/seo-score/${data.domain}/history`] });
      queryClient.refetchQueries({ queryKey: [`/api/seo-score/${data.domain}`] });
      queryClient.refetchQueries({ queryKey: [`/api/seo-score/${data.domain}/history`] });
      setSelectedDomain(data.domain);
      toast({
        title: "Score Calculated",
        description: `SEO score for ${data.domain}: ${data.overallScore}/100`,
      });
    },
    onError: () => {
      toast({
        variant: "destructive",
        title: "Calculation Failed",
        description: "Failed to calculate SEO score. Please try again.",
      });
    },
  });

  const { data: currentScore } = useQuery<SeoScore>({
    queryKey: [`/api/seo-score/${selectedDomain}`],
    enabled: !!selectedDomain,
  });

  const { data: scoreHistory = [] } = useQuery<SeoScore[]>({
    queryKey: [`/api/seo-score/${selectedDomain}/history`],
    enabled: !!selectedDomain,
  });

  const handleCalculate = () => {
    if (!domain.trim()) {
      toast({
        variant: "destructive",
        title: "Invalid Input",
        description: "Please enter a domain name",
      });
      return;
    }
    calculateMutation.mutate(domain.trim());
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return "text-green-600";
    if (score >= 60) return "text-yellow-600";
    return "text-red-600";
  };

  const getScoreBgColor = (score: number) => {
    if (score >= 80) return "bg-green-600";
    if (score >= 60) return "bg-yellow-600";
    return "bg-red-600";
  };

  const chartData = scoreHistory.map((score) => ({
    date: format(new Date(score.createdAt), "MMM d"),
    overall: score.overallScore,
    technical: score.technicalScore,
    ranking: score.rankingScore,
    content: score.contentScore,
    activity: score.activityScore,
  }));

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">SEO Score Dashboard</h1>
        <p className="text-muted-foreground mt-2">
          Unified scoring system aggregating all your SEO metrics
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Calculate SEO Score</CardTitle>
          <CardDescription>
            Enter your domain to calculate a comprehensive SEO score based on audits, rankings, content, and activity
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex gap-2">
            <Input
              placeholder="example.com"
              value={domain}
              onChange={(e) => setDomain(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleCalculate()}
              data-testid="input-domain"
              className="flex-1"
            />
            <Button
              onClick={handleCalculate}
              disabled={calculateMutation.isPending}
              data-testid="button-calculate"
            >
              {calculateMutation.isPending ? "Calculating..." : "Calculate Score"}
            </Button>
          </div>
        </CardContent>
      </Card>

      {currentScore && (
        <>
          <div className="grid gap-6 md:grid-cols-2">
            <Card>
              <CardHeader>
                <CardTitle>Overall SEO Score</CardTitle>
                <CardDescription data-testid="text-domain">{currentScore.domain}</CardDescription>
              </CardHeader>
              <CardContent>
                <div className="flex items-center justify-center">
                  <div className="relative">
                    <div className="flex items-center justify-center h-48 w-48">
                      <div className={`text-6xl font-bold ${getScoreColor(currentScore.overallScore)}`} data-testid="text-overall-score">
                        {currentScore.overallScore}
                      </div>
                    </div>
                    <div className="absolute inset-0 flex items-center justify-center">
                      <svg className="h-48 w-48 -rotate-90">
                        <circle
                          cx="96"
                          cy="96"
                          r="88"
                          stroke="currentColor"
                          strokeWidth="8"
                          fill="none"
                          className="text-muted"
                        />
                        <circle
                          cx="96"
                          cy="96"
                          r="88"
                          stroke="currentColor"
                          strokeWidth="8"
                          fill="none"
                          strokeDasharray={`${(currentScore.overallScore / 100) * 553} 553`}
                          className={getScoreColor(currentScore.overallScore)}
                        />
                      </svg>
                    </div>
                  </div>
                </div>
                <p className="text-center text-sm text-muted-foreground mt-4" data-testid="text-last-calculated">
                  Last calculated: {format(new Date(currentScore.createdAt), "MMM d, yyyy 'at' h:mm a")}
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Category Breakdown</CardTitle>
                <CardDescription>Score distribution across SEO categories</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <div className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-2">
                      <Target className="h-4 w-4" />
                      <span>Technical SEO</span>
                    </div>
                    <span className="font-medium">{currentScore.technicalScore}/100 (35%)</span>
                  </div>
                  <Progress value={currentScore.technicalScore} className="h-2" data-testid="progress-technical" />
                </div>

                <div className="space-y-2">
                  <div className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-2">
                      <TrendingUp className="h-4 w-4" />
                      <span>Ranking Performance</span>
                    </div>
                    <span className="font-medium">{currentScore.rankingScore}/100 (30%)</span>
                  </div>
                  <Progress value={currentScore.rankingScore} className="h-2" data-testid="progress-ranking" />
                </div>

                <div className="space-y-2">
                  <div className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-2">
                      <FileText className="h-4 w-4" />
                      <span>Content Quality</span>
                    </div>
                    <span className="font-medium">{currentScore.contentScore}/100 (20%)</span>
                  </div>
                  <Progress value={currentScore.contentScore} className="h-2" data-testid="progress-content" />
                </div>

                <div className="space-y-2">
                  <div className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-2">
                      <Activity className="h-4 w-4" />
                      <span>Platform Activity</span>
                    </div>
                    <span className="font-medium">{currentScore.activityScore}/100 (15%)</span>
                  </div>
                  <Progress value={currentScore.activityScore} className="h-2" data-testid="progress-activity" />
                </div>
              </CardContent>
            </Card>
          </div>

          {scoreHistory.length > 1 && (
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <BarChart3 className="h-5 w-5" />
                  Score Trends
                </CardTitle>
                <CardDescription>
                  Historical SEO score performance over time
                </CardDescription>
              </CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={300} data-testid="chart-score-trends">
                  <LineChart data={chartData}>
                    <CartesianGrid strokeDasharray="3 3" />
